-- Backfill conditions_to_appear and conditions_to_cancel for AI-generated C2E injects
-- that have no triggering mechanism (trigger_time_minutes, trigger_condition, and
-- conditions_to_appear are all NULL). These "dead" injects were generated by an older
-- version of the AI scenario generator that did not produce conditions.
--
-- Strategy: match inject content keywords + target_teams to assign the most appropriate
-- condition keys from the conditionEvaluatorService registry. Multiple tiers go from
-- most-specific patterns to team-level fallbacks so every dead inject gets a condition.

DO $$
DECLARE
  updated_count INTEGER := 0;
  tier_count    INTEGER;
BEGIN

-- =============================================================================
-- MEDIA TEAM — Tier 1: specific content patterns
-- =============================================================================

-- 1a) Misinformation / rumour / false narrative injects
UPDATE scenario_injects SET
  conditions_to_appear  = '{"threshold": 1, "conditions": ["media_misinformation_not_addressed", "no_media_management_decision"]}'::jsonb,
  conditions_to_cancel  = '["media_misinformation_addressed"]'::jsonb,
  eligible_after_minutes = COALESCE(eligible_after_minutes, 10)
WHERE ai_generated = true
  AND trigger_time_minutes  IS NULL
  AND trigger_condition     IS NULL
  AND conditions_to_appear  IS NULL
  AND target_teams @> ARRAY['media']
  AND NOT target_teams @> ARRAY['evacuation']
  AND NOT target_teams @> ARRAY['triage']
  AND (
    content ILIKE '%misinformation%'
    OR content ILIKE '%rumour%'
    OR content ILIKE '%rumor%'
    OR content ILIKE '%false narrative%'
    OR content ILIKE '%false claim%'
    OR content ILIKE '%viral%'
    OR content ILIKE '%debunk%'
    OR content ILIKE '%disinformation%'
    OR content ILIKE '%fake news%'
    OR content ILIKE '%conspiracy%'
  );
GET DIAGNOSTICS tier_count = ROW_COUNT;
updated_count := updated_count + tier_count;
RAISE NOTICE '1a) Media misinformation injects: %', tier_count;

-- 1b) Spokesperson / designated authority injects
UPDATE scenario_injects SET
  conditions_to_appear  = '{"all": ["media_no_spokesperson_designated"]}'::jsonb,
  conditions_to_cancel  = '["media_spokesperson_designated"]'::jsonb,
  eligible_after_minutes = COALESCE(eligible_after_minutes, 8)
WHERE ai_generated = true
  AND trigger_time_minutes  IS NULL
  AND trigger_condition     IS NULL
  AND conditions_to_appear  IS NULL
  AND target_teams @> ARRAY['media']
  AND NOT target_teams @> ARRAY['evacuation']
  AND NOT target_teams @> ARRAY['triage']
  AND (
    content ILIKE '%spokesperson%'
    OR content ILIKE '%designated%'
    OR content ILIKE '%single voice%'
    OR content ILIKE '%one voice%'
    OR content ILIKE '%authorised speaker%'
    OR content ILIKE '%authorized speaker%'
    OR content ILIKE '%official speaker%'
  );
GET DIAGNOSTICS tier_count = ROW_COUNT;
updated_count := updated_count + tier_count;
RAISE NOTICE '1b) Media spokesperson injects: %', tier_count;

-- 1c) Regular updates / communication schedule injects
UPDATE scenario_injects SET
  conditions_to_appear  = '{"all": ["media_no_regular_updates_decision"]}'::jsonb,
  conditions_to_cancel  = '["media_regular_updates_planned"]'::jsonb,
  eligible_after_minutes = COALESCE(eligible_after_minutes, 12)
WHERE ai_generated = true
  AND trigger_time_minutes  IS NULL
  AND trigger_condition     IS NULL
  AND conditions_to_appear  IS NULL
  AND target_teams @> ARRAY['media']
  AND NOT target_teams @> ARRAY['evacuation']
  AND NOT target_teams @> ARRAY['triage']
  AND (
    content ILIKE '%regular update%'
    OR content ILIKE '%update schedule%'
    OR content ILIKE '%scheduled update%'
    OR content ILIKE '%communication plan%'
    OR content ILIKE '%update cadence%'
    OR content ILIKE '%30 min%'
    OR content ILIKE '%60 min%'
    OR content ILIKE '%next update%'
    OR content ILIKE '%periodic%'
  );
GET DIAGNOSTICS tier_count = ROW_COUNT;
updated_count := updated_count + tier_count;
RAISE NOTICE '1c) Media regular updates injects: %', tier_count;

-- 1d) Journalist / press / filming / photographer injects
UPDATE scenario_injects SET
  conditions_to_appear  = '{"all": ["media_journalist_arrived"]}'::jsonb,
  conditions_to_cancel  = '["media_statement_issued"]'::jsonb,
  eligible_after_minutes = COALESCE(eligible_after_minutes, 10)
WHERE ai_generated = true
  AND trigger_time_minutes  IS NULL
  AND trigger_condition     IS NULL
  AND conditions_to_appear  IS NULL
  AND target_teams @> ARRAY['media']
  AND NOT target_teams @> ARRAY['evacuation']
  AND NOT target_teams @> ARRAY['triage']
  AND (
    content ILIKE '%journalist%'
    OR content ILIKE '%photographer%'
    OR content ILIKE '%camera crew%'
    OR content ILIKE '%press conference%'
    OR content ILIKE '%reporter%'
    OR content ILIKE '%news crew%'
    OR content ILIKE '%filming%'
    OR content ILIKE '%live broadcast%'
  );
GET DIAGNOSTICS tier_count = ROW_COUNT;
updated_count := updated_count + tier_count;
RAISE NOTICE '1d) Media journalist/press injects: %', tier_count;

-- 1e) Political scrutiny / PM / credibility / public trust / delay injects
UPDATE scenario_injects SET
  conditions_to_appear  = '{"all": ["media_no_statement_by_T12"]}'::jsonb,
  conditions_to_cancel  = '["media_statement_issued"]'::jsonb,
  eligible_after_minutes = COALESCE(eligible_after_minutes, 12)
WHERE ai_generated = true
  AND trigger_time_minutes  IS NULL
  AND trigger_condition     IS NULL
  AND conditions_to_appear  IS NULL
  AND target_teams @> ARRAY['media']
  AND NOT target_teams @> ARRAY['evacuation']
  AND NOT target_teams @> ARRAY['triage']
  AND (
    content ILIKE '%political%'
    OR content ILIKE '%scrutiny%'
    OR content ILIKE '%PM%'
    OR content ILIKE '%prime minister%'
    OR content ILIKE '%credibility%'
    OR content ILIKE '%public trust%'
    OR content ILIKE '%erosion%'
    OR content ILIKE '%accountability%'
    OR content ILIKE '%disorganis%'
    OR content ILIKE '%disorganiz%'
    OR content ILIKE '%information vacuum%'
    OR content ILIKE '%silence%'
    OR content ILIKE '%no statement%'
    OR content ILIKE '%no official%'
    OR content ILIKE '%delayed response%'
  );
GET DIAGNOSTICS tier_count = ROW_COUNT;
updated_count := updated_count + tier_count;
RAISE NOTICE '1e) Media political/trust injects: %', tier_count;

-- 1f) Fallback: remaining media-only injects → general "no media management" condition
UPDATE scenario_injects SET
  conditions_to_appear  = '{"all": ["no_media_management_decision"]}'::jsonb,
  conditions_to_cancel  = '["media_statement_issued"]'::jsonb,
  eligible_after_minutes = COALESCE(eligible_after_minutes, 10)
WHERE ai_generated = true
  AND trigger_time_minutes  IS NULL
  AND trigger_condition     IS NULL
  AND conditions_to_appear  IS NULL
  AND target_teams @> ARRAY['media']
  AND NOT target_teams @> ARRAY['evacuation']
  AND NOT target_teams @> ARRAY['triage'];
GET DIAGNOSTICS tier_count = ROW_COUNT;
updated_count := updated_count + tier_count;
RAISE NOTICE '1f) Media fallback injects: %', tier_count;

-- =============================================================================
-- EVACUATION TEAM — Tier 2: specific content patterns
-- =============================================================================

-- 2a) Second device / suspicious individual / exit B
