  AND (
    content ILIKE '%second device%'
    OR content ILIKE '%second bomb%'
    OR content ILIKE '%suspicious package%'
    OR content ILIKE '%suspicious bag%'
    OR content ILIKE '%unattended bag%'
    OR content ILIKE '%suicide attacker%'
    OR content ILIKE '%secondary threat%'
    OR content ILIKE '%secondary attack%'
    OR content ILIKE '%exit b%'
    OR content ILIKE '%Exit B%'
