-- 2c) Perimeter / cordon / security zone
UPDATE scenario_injects SET
  conditions_to_appear  = '{"all": ["no_perimeter_establishment_decision"]}'::jsonb,
  conditions_to_cancel  = '["area_cleared"]'::jsonb,
  eligible_after_minutes = COALESCE(eligible_after_minutes, 8)
WHERE ai_generated = true
  AND trigger_time_minutes  IS NULL
  AND trigger_condition     IS NULL
  AND conditions_to_appear  IS NULL
  AND target_teams @> ARRAY['evacuation']
  AND NOT target_teams @> ARRAY['media']
  AND NOT target_teams @> ARRAY['triage']
  AND (
    content ILIKE '%perimeter%'
    OR content ILIKE '%cordon%'
    OR content ILIKE '%security zone%'
    OR content ILIKE '%inner cordon%'
