  AND conditions_to_appear  IS NULL
  AND target_teams @> ARRAY['evacuation']
  AND NOT target_teams @> ARRAY['media']
  AND NOT target_teams @> ARRAY['triage']
  AND (
    content ILIKE '%bottleneck%'
    OR content ILIKE '%congestion%'
    OR content ILIKE '%congested%'
    OR content ILIKE '%flow control%'
    OR content ILIKE '%stampede%'
    OR content ILIKE '%crush%'
    OR content ILIKE '%exit capacity%'
    OR content ILIKE '%stagger%'
    OR content ILIKE '%egress%'
    OR content ILIKE '%crowd density%'
    OR content ILIKE '%overcrowd%'
    OR content ILIKE '%trampl%'
  );
GET DIAGNOSTICS tier_count = ROW_COUNT;
updated_count := updated_count + tier_count;
