  AND (target_teams IS NULL OR array_length(target_teams, 1) IS NULL OR array_length(target_teams, 1) = 0
       OR (target_teams @> ARRAY['evacuation'] AND target_teams @> ARRAY['triage'] AND target_teams @> ARRAY['media']))
  AND (
    content ILIKE '%misinformation%'
    OR content ILIKE '%rumour%'
