GET DIAGNOSTICS tier_count = ROW_COUNT;
updated_count := updated_count + tier_count;
RAISE NOTICE '5a) Universal misinformation injects: %', tier_count;

-- 5b) Universal injects about security / second device / threat
UPDATE scenario_injects SET
  conditions_to_appear  = '{"all": ["area_not_cleared"]}'::jsonb,
  conditions_to_cancel  = '["area_cleared"]'::jsonb,
  eligible_after_minutes = COALESCE(eligible_after_minutes, 10)
WHERE ai_generated = true
  AND trigger_time_minutes  IS NULL
  AND trigger_condition     IS NULL
  AND conditions_to_appear  IS NULL
  AND (target_teams IS NULL OR array_length(target_teams, 1) IS NULL OR array_length(target_teams, 1) = 0
       OR (target_teams @> ARRAY['evacuation'] AND target_teams @> ARRAY['triage'] AND target_teams @> ARRAY['media']))
  AND (
    content ILIKE '%second device%'
    OR content ILIKE '%second bomb%'
    OR content ILIKE '%suicide attacker%'
    OR content ILIKE '%suspicious%'
    OR content ILIKE '%secondary threat%'
    OR content ILIKE '%secondary attack%'
    OR content ILIKE '%active shooter%'
    OR content ILIKE '%ongoing threat%'
  );
GET DIAGNOSTICS tier_count = ROW_COUNT;
updated_count := updated_count + tier_count;
RAISE NOTICE '5b) Universal security/threat injects: %', tier_count;

-- 5c) Universal evacuation-themed injects
UPDATE scenario_injects SET
  conditions_to_appear  = '{"threshold": 1, "conditions": ["evacuation_no_flow_control_decision", "evacuation_exit_bottleneck_active", "objective_evacuation_not_completed"]}'::jsonb,
  conditions_to_cancel  = '["evacuation_flow_control_decided"]'::jsonb,
  eligible_after_minutes = COALESCE(eligible_after_minutes, 8)
WHERE ai_generated = true
  AND trigger_time_minutes  IS NULL
  AND trigger_condition     IS NULL
  AND conditions_to_appear  IS NULL
  AND (target_teams IS NULL OR array_length(target_teams, 1) IS NULL OR array_length(target_teams, 1) = 0
       OR (target_teams @> ARRAY['evacuation'] AND target_teams @> ARRAY['triage'] AND target_teams @> ARRAY['media']))
  AND (
    content ILIKE '%evacuat%'
    OR content ILIKE '%bottleneck%'
    OR content ILIKE '%exit%'
    OR content ILIKE '%crowd%'
    OR content ILIKE '%stampede%'
    OR content ILIKE '%crush%'
  );
GET DIAGNOSTICS tier_count = ROW_COUNT;
updated_count := updated_count + tier_count;
RAISE NOTICE '5c) Universal evacuation injects: %', tier_count;

-- 5d) Universal triage-themed injects
UPDATE scenario_injects SET
  conditions_to_appear  = '{"threshold": 1, "conditions": ["triage_no_prioritisation_decision", "triage_surge_active", "triage_supply_critical"]}'::jsonb,
  conditions_to_cancel  = '["triage_prioritisation_decided"]'::jsonb,
  eligible_after_minutes = COALESCE(eligible_after_minutes, 8)
WHERE ai_generated = true
  AND trigger_time_minutes  IS NULL
  AND trigger_condition     IS NULL
  AND conditions_to_appear  IS NULL
  AND (target_teams IS NULL OR array_length(target_teams, 1) IS NULL OR array_length(target_teams, 1) = 0
       OR (target_teams @> ARRAY['evacuation'] AND target_teams @> ARRAY['triage'] AND target_teams @> ARRAY['media']))
  AND (
    content ILIKE '%triage%'
    OR content ILIKE '%casualt%'
    OR content ILIKE '%injur%'
    OR content ILIKE '%medical%'
    OR content ILIKE '%patient%'
    OR content ILIKE '%first aid%'
  );
GET DIAGNOSTICS tier_count = ROW_COUNT;
updated_count := updated_count + tier_count;
RAISE NOTICE '5d) Universal triage injects: %', tier_count;

-- 5e) Catch-all: any remaining dead injects → multi-condition threshold
UPDATE scenario_injects SET
  conditions_to_appear  = '{"threshold": 2, "conditions": ["no_media_management_decision", "evacuation_no_flow_control_decision", "triage_no_prioritisation_decision", "no_perimeter_establishment_decision"]}'::jsonb,
  conditions_to_cancel  = '[]'::jsonb,
  eligible_after_minutes = COALESCE(eligible_after_minutes, 10)
WHERE ai_generated = true
  AND trigger_time_minutes  IS NULL
  AND trigger_condition     IS NULL
  AND conditions_to_appear  IS NULL;
GET DIAGNOSTICS tier_count = ROW_COUNT;
updated_count := updated_count + tier_count;
RAISE NOTICE '5e) Catch-all fallback injects: %', tier_count;

RAISE NOTICE '=== Total dead injects updated with conditions: % ===', updated_count;

END $$;

-- Summary: how many injects now have conditions vs. still dead
SELECT
  'Post-migration summary' AS status,
  COUNT(*) FILTER (WHERE conditions_to_appear IS NOT NULL) AS with_conditions,
  COUNT(*) FILTER (WHERE conditions_to_appear IS NULL AND trigger_time_minutes IS NULL AND trigger_condition IS NULL) AS still_dead,
  COUNT(*) FILTER (WHERE trigger_time_minutes IS NOT NULL) AS time_based,
  COUNT(*) FILTER (WHERE trigger_condition IS NOT NULL) AS keyword_based,
  COUNT(*) AS total
FROM scenario_injects
WHERE ai_generated = true;
